import sys

def solve():
    N, S, R = map(int, sys.stdin.readline().split())
    A = list(map(int, sys.stdin.readline().split()))

    def is_calm(block):
        return sum(block) <= S and max(block) - min(block) <= R

    calm_blocks = 0
    for i in range(N):
        for j in range(i, N):
            block = A[i:j+1]
            if is_calm(block):
                calm_blocks += 1

    print(calm_blocks)

if __name__ == "__main__":
    solve()
